/**
 * Tests for Preview Engine — Core playback logic
 *
 * Covers:
 * - Scene timing computations
 * - Time ↔ scene mapping
 * - Playback state transitions (play, pause, stop, seek, skip)
 * - Speed control
 * - Loop behavior
 * - Utility functions (format, seek bar, scene markers)
 * - Edge cases (empty scenes, zero duration, negative time)
 */

import {
  computeSceneTimings,
  getTotalDuration,
  getSceneStartTime,
  mapTimeToScene,
  sceneToGlobalTime,
  createInitialState,
  advanceTime,
  seekTo,
  seekToScene,
  togglePlayPause,
  play,
  pause,
  stop,
  setSpeed,
  toggleLoop,
  skip,
  nextScene,
  previousScene,
  formatPreviewTime,
  getSeekPosition,
  seekPositionToTime,
  getSceneMarkers,
  getNearestSpeedPreset,
  isSpeedPreset,
  cycleSpeedPreset,
  DEFAULT_SCENE_DURATION,
  MIN_SPEED,
  MAX_SPEED,
  SPEED_PRESETS,
} from '@/lib/editor/preview-engine';
import type { PreviewScene, PreviewState } from '@/lib/editor/preview-engine';

// ============================================================================
// HELPERS
// ============================================================================

function makeScenes(...durations: number[]): PreviewScene[] {
  return durations.map((d, i) => ({
    id: `scene-${i}`,
    duration: d,
  }));
}

function makeScenesWithAudio(...configs: { duration: number; audioUrl?: string }[]): PreviewScene[] {
  return configs.map((c, i) => ({
    id: `scene-${i}`,
    duration: c.duration,
    audioUrl: c.audioUrl,
  }));
}

function playingState(scenes: PreviewScene[]): PreviewState {
  const state = createInitialState(scenes);
  return play(state);
}

// ============================================================================
// SCENE TIMINGS
// ============================================================================

describe('computeSceneTimings', () => {
  it('computes timings for multiple scenes', () => {
    const scenes = makeScenes(5, 10, 3);
    const timings = computeSceneTimings(scenes);

    expect(timings).toHaveLength(3);
    expect(timings[0]).toEqual({
      sceneIndex: 0,
      sceneId: 'scene-0',
      startTime: 0,
      endTime: 5,
      duration: 5,
    });
    expect(timings[1]).toEqual({
      sceneIndex: 1,
      sceneId: 'scene-1',
      startTime: 5,
      endTime: 15,
      duration: 10,
    });
    expect(timings[2]).toEqual({
      sceneIndex: 2,
      sceneId: 'scene-2',
      startTime: 15,
      endTime: 18,
      duration: 3,
    });
  });

  it('returns empty array for no scenes', () => {
    expect(computeSceneTimings([])).toEqual([]);
  });

  it('handles single scene', () => {
    const timings = computeSceneTimings(makeScenes(7));
    expect(timings).toHaveLength(1);
    expect(timings[0].startTime).toBe(0);
    expect(timings[0].endTime).toBe(7);
  });

  it('uses Math.max(0, duration) for zero/negative durations with fallback', () => {
    const scenes: PreviewScene[] = [
      { id: 's1', duration: 0 },
      { id: 's2', duration: -1 },
    ];
    const timings = computeSceneTimings(scenes);
    // duration 0 → falsy → OR fallback to DEFAULT_SCENE_DURATION (5) → Math.max(0,5) = 5
    expect(timings[0].duration).toBe(DEFAULT_SCENE_DURATION);
    // duration -1 → truthy → stays -1 → Math.max(0, -1) = 0
    expect(timings[1].duration).toBe(0);
  });
});

describe('getTotalDuration', () => {
  it('sums all scene durations', () => {
    expect(getTotalDuration(makeScenes(5, 10, 3))).toBe(18);
  });

  it('returns 0 for empty scenes', () => {
    expect(getTotalDuration([])).toBe(0);
  });

  it('handles single scene', () => {
    expect(getTotalDuration(makeScenes(12))).toBe(12);
  });
});

describe('getSceneStartTime', () => {
  it('returns 0 for first scene', () => {
    expect(getSceneStartTime(makeScenes(5, 10, 3), 0)).toBe(0);
  });

  it('returns cumulative time for later scenes', () => {
    const scenes = makeScenes(5, 10, 3);
    expect(getSceneStartTime(scenes, 1)).toBe(5);
    expect(getSceneStartTime(scenes, 2)).toBe(15);
  });

  it('returns 0 for out-of-range indices', () => {
    const scenes = makeScenes(5, 10);
    expect(getSceneStartTime(scenes, -1)).toBe(0);
    expect(getSceneStartTime(scenes, 5)).toBe(0);
  });
});

