describe('mapTimeToScene', () => {
  const scenes = makeScenes(5, 10, 3);

  it('maps time 0 to first scene', () => {
    const result = mapTimeToScene(scenes, 0);
    expect(result.sceneIndex).toBe(0);
    expect(result.sceneId).toBe('scene-0');
    expect(result.sceneLocalTime).toBe(0);
    expect(result.sceneProgress).toBe(0);
  });

  it('maps time within first scene', () => {
    const result = mapTimeToScene(scenes, 2.5);
    expect(result.sceneIndex).toBe(0);
    expect(result.sceneLocalTime).toBe(2.5);
    expect(result.sceneProgress).toBe(0.5);
  });

  it('maps time at scene boundary to next scene', () => {
    const result = mapTimeToScene(scenes, 5);
    expect(result.sceneIndex).toBe(1);
    expect(result.sceneLocalTime).toBe(0);
    expect(result.sceneProgress).toBe(0);
  });

  it('maps time within second scene', () => {
    const result = mapTimeToScene(scenes, 10);
    expect(result.sceneIndex).toBe(1);
    expect(result.sceneLocalTime).toBe(5);
    expect(result.sceneProgress).toBe(0.5);
  });

  it('maps time at end to last scene with progress 1', () => {
    const result = mapTimeToScene(scenes, 18);
    expect(result.sceneIndex).toBe(2);
    expect(result.sceneLocalTime).toBe(3);
    expect(result.sceneProgress).toBe(1);
  });

  it('clamps negative time to 0', () => {
    const result = mapTimeToScene(scenes, -5);
    expect(result.sceneIndex).toBe(0);
    expect(result.sceneLocalTime).toBe(0);
    expect(result.sceneProgress).toBe(0);
  });

  it('clamps time beyond total to end', () => {
    const result = mapTimeToScene(scenes, 100);
    expect(result.sceneIndex).toBe(2);
    expect(result.sceneProgress).toBe(1);
  });

  it('handles empty scenes', () => {
    const result = mapTimeToScene([], 5);
    expect(result.sceneIndex).toBe(-1);
    expect(result.sceneId).toBe('');
  });

  it('handles single scene', () => {
    const result = mapTimeToScene(makeScenes(10), 5);
    expect(result.sceneIndex).toBe(0);
    expect(result.sceneLocalTime).toBe(5);
    expect(result.sceneProgress).toBe(0.5);
  });

  it('returns correct sceneStartTime', () => {
    const result = mapTimeToScene(scenes, 16);
    expect(result.sceneStartTime).toBe(15);
    expect(result.sceneLocalTime).toBe(1);
  });
});

describe('sceneToGlobalTime', () => {
  const scenes = makeScenes(5, 10, 3);

  it('converts scene 0 start to global time 0', () => {
    expect(sceneToGlobalTime(scenes, 0)).toBe(0);
  });

  it('converts scene 1 start to global time 5', () => {
    expect(sceneToGlobalTime(scenes, 1)).toBe(5);
  });

  it('applies local offset', () => {
    expect(sceneToGlobalTime(scenes, 1, 3)).toBe(8);
  });

  it('clamps offset to scene duration', () => {
    expect(sceneToGlobalTime(scenes, 1, 20)).toBe(15); // 5 + min(20, 10) = 15
  });

  it('clamps negative offset to 0', () => {
    expect(sceneToGlobalTime(scenes, 1, -5)).toBe(5);
  });
});

