describe('createInitialState', () => {
  it('creates stopped state with correct totals', () => {
    const state = createInitialState(makeScenes(5, 10));
    expect(state.status).toBe('stopped');
    expect(state.currentTime).toBe(0);
    expect(state.totalDuration).toBe(15);
    expect(state.playbackSpeed).toBe(1);
    expect(state.loop).toBe(false);
    expect(state.currentSceneIndex).toBe(0);
  });

  it('handles empty scenes', () => {
    const state = createInitialState([]);
    expect(state.totalDuration).toBe(0);
    expect(state.currentSceneIndex).toBe(-1);
  });
});

describe('play / pause / stop / togglePlayPause', () => {
  const scenes = makeScenes(5, 10);

  it('play sets status to playing', () => {
    const state = createInitialState(scenes);
    const result = play(state);
    expect(result.status).toBe('playing');
  });

  it('pause sets status to paused when playing', () => {
    const state = play(createInitialState(scenes));
    const result = pause(state);
    expect(result.status).toBe('paused');
  });

  it('pause does nothing when stopped', () => {
    const state = createInitialState(scenes);
    const result = pause(state);
    expect(result.status).toBe('stopped');
  });

  it('stop resets to beginning', () => {
    const state = play(createInitialState(scenes));
    const seeked = seekTo(state, 8, scenes);
    const result = stop(seeked, scenes);
    expect(result.status).toBe('stopped');
    expect(result.currentTime).toBe(0);
    expect(result.currentSceneIndex).toBe(0);
  });

  it('togglePlayPause switches between play and pause', () => {
    const state = createInitialState(scenes);
    const playing = togglePlayPause(state);
    expect(playing.status).toBe('playing');
    const paused = togglePlayPause(playing);
    expect(paused.status).toBe('paused');
  });
});

describe('advanceTime', () => {
  const scenes = makeScenes(5, 10, 3);

  it('advances time by delta * speed', () => {
    const state = playingState(scenes);
    const result = advanceTime(state, 0.5, scenes);
    expect(result.currentTime).toBeCloseTo(0.5);
    expect(result.status).toBe('playing');
  });

  it('respects playback speed', () => {
    let state = playingState(scenes);
    state = setSpeed(state, 2);
    const result = advanceTime(state, 0.5, scenes);
    expect(result.currentTime).toBeCloseTo(1); // 0.5 * 2
  });

  it('pauses at end when not looping', () => {
    let state = playingState(scenes);
    state = seekTo(state, 17, scenes);
    state = { ...state, status: 'playing' };
    const result = advanceTime(state, 2, scenes);
    expect(result.currentTime).toBe(18);
    expect(result.status).toBe('paused');
  });

  it('loops to beginning when looping', () => {
    let state = playingState(scenes);
    state = toggleLoop(state);
    state = seekTo(state, 17, scenes);
    state = { ...state, status: 'playing' };
    const result = advanceTime(state, 2, scenes);
    expect(result.currentTime).toBeCloseTo(1); // 19 % 18 = 1
    expect(result.status).toBe('playing');
  });

  it('does nothing when not playing', () => {
    const state = createInitialState(scenes);
    const result = advanceTime(state, 1, scenes);
    expect(result.currentTime).toBe(0);
  });

  it('updates scene index on scene change', () => {
    let state = playingState(scenes);
    state = seekTo(state, 4.5, scenes);
    state = { ...state, status: 'playing' };
    const result = advanceTime(state, 1, scenes);
    expect(result.currentSceneIndex).toBe(1);
  });
});

describe('seekTo', () => {
  const scenes = makeScenes(5, 10, 3);

  it('seeks to specific time', () => {
    const state = createInitialState(scenes);
    const result = seekTo(state, 8, scenes);
    expect(result.currentTime).toBe(8);
    expect(result.currentSceneIndex).toBe(1);
    expect(result.sceneLocalTime).toBe(3);
  });

  it('clamps to 0', () => {
    const state = createInitialState(scenes);
    const result = seekTo(state, -5, scenes);
    expect(result.currentTime).toBe(0);
  });

  it('clamps to total duration', () => {
    const state = createInitialState(scenes);
    const result = seekTo(state, 100, scenes);
    expect(result.currentTime).toBe(18);
  });

  it('preserves playback status', () => {
    const state = playingState(scenes);
    const result = seekTo(state, 8, scenes);
    expect(result.status).toBe('playing');
  });
});

describe('seekToScene', () => {
  const scenes = makeScenes(5, 10, 3);

  it('seeks to start of specific scene', () => {
    const state = createInitialState(scenes);
    const result = seekToScene(state, 2, scenes);
    expect(result.currentTime).toBe(15);
    expect(result.currentSceneIndex).toBe(2);
    expect(result.sceneLocalTime).toBe(0);
  });

  it('clamps scene index to valid range', () => {
    const state = createInitialState(scenes);
    const result = seekToScene(state, 10, scenes);
    expect(result.currentSceneIndex).toBe(2);
  });

  it('clamps negative index to 0', () => {
    const state = createInitialState(scenes);
    const result = seekToScene(state, -3, scenes);
    expect(result.currentSceneIndex).toBe(0);
  });
});

describe('skip', () => {
  const scenes = makeScenes(5, 10, 3);

  it('skips forward', () => {
    const state = createInitialState(scenes);
    const result = skip(state, 3, scenes);
    expect(result.currentTime).toBe(3);
  });

  it('skips backward', () => {
    const state = seekTo(createInitialState(scenes), 8, scenes);
    const result = skip(state, -3, scenes);
    expect(result.currentTime).toBe(5);
  });

  it('clamps at boundaries', () => {
    const state = createInitialState(scenes);
    const result = skip(state, -10, scenes);
    expect(result.currentTime).toBe(0);

    const result2 = skip(state, 100, scenes);
    expect(result2.currentTime).toBe(18);
  });
});

describe('nextScene / previousScene', () => {
  const scenes = makeScenes(5, 10, 3);

  it('nextScene goes to next scene', () => {
    const state = createInitialState(scenes);
    const result = nextScene(state, scenes);
    expect(result.currentSceneIndex).toBe(1);
    expect(result.currentTime).toBe(5);
  });

  it('nextScene stays at last scene', () => {
    let state = seekToScene(createInitialState(scenes), 2, scenes);
    const result = nextScene(state, scenes);
    expect(result.currentSceneIndex).toBe(2);
  });

  it('previousScene goes to start of current if >2s in', () => {
    let state = seekTo(createInitialState(scenes), 8, scenes);
    // scene 1, localTime = 3 (> 2)
    const result = previousScene(state, scenes);
    expect(result.currentSceneIndex).toBe(1);
    expect(result.sceneLocalTime).toBe(0);
    expect(result.currentTime).toBe(5);
  });

  it('previousScene goes to previous scene if ≤2s in', () => {
    let state = seekTo(createInitialState(scenes), 6, scenes);
    // scene 1, localTime = 1 (≤ 2)
    const result = previousScene(state, scenes);
    expect(result.currentSceneIndex).toBe(0);
    expect(result.currentTime).toBe(0);
  });

  it('previousScene stays at first scene', () => {
    const state = createInitialState(scenes);
    const result = previousScene(state, scenes);
    expect(result.currentSceneIndex).toBe(0);
  });

  it('handles empty scenes', () => {
    const state = createInitialState([]);
    expect(nextScene(state, []).currentSceneIndex).toBe(-1);
    expect(previousScene(state, []).currentSceneIndex).toBe(-1);
  });
});

