describe('formatPreviewTime', () => {
  it('formats 0 seconds', () => {
    expect(formatPreviewTime(0)).toBe('0:00');
  });

  it('formats seconds < 60', () => {
    expect(formatPreviewTime(5)).toBe('0:05');
    expect(formatPreviewTime(30)).toBe('0:30');
    expect(formatPreviewTime(59)).toBe('0:59');
  });

  it('formats minutes', () => {
    expect(formatPreviewTime(60)).toBe('1:00');
    expect(formatPreviewTime(90)).toBe('1:30');
    expect(formatPreviewTime(125)).toBe('2:05');
  });

  it('formats with milliseconds', () => {
    expect(formatPreviewTime(5.7, true)).toBe('0:05.7');
    // 90.3 has floating point imprecision: 90.3 % 1 ≈ 0.299...
    // Math.floor(0.299... * 10) = 2, so the output is '1:30.2'
    expect(formatPreviewTime(90.3, true)).toBe('1:30.2');
    expect(formatPreviewTime(90.5, true)).toBe('1:30.5');
  });

  it('clamps negative to 0', () => {
    expect(formatPreviewTime(-5)).toBe('0:00');
  });
});

describe('getSeekPosition / seekPositionToTime', () => {
  it('returns 0 for 0 time', () => {
    expect(getSeekPosition(0, 18)).toBe(0);
  });

  it('returns 1 for end time', () => {
    expect(getSeekPosition(18, 18)).toBe(1);
  });

  it('returns proportional position', () => {
    expect(getSeekPosition(9, 18)).toBeCloseTo(0.5);
  });

  it('handles 0 total duration', () => {
    expect(getSeekPosition(5, 0)).toBe(0);
  });

  it('clamps position to 0-1', () => {
    expect(getSeekPosition(-5, 10)).toBe(0);
    expect(getSeekPosition(20, 10)).toBe(1);
  });

  it('converts position to time', () => {
    expect(seekPositionToTime(0.5, 20)).toBe(10);
    expect(seekPositionToTime(0, 20)).toBe(0);
    expect(seekPositionToTime(1, 20)).toBe(20);
  });

  it('clamps position in seekPositionToTime', () => {
    expect(seekPositionToTime(-0.5, 20)).toBe(0);
    expect(seekPositionToTime(2, 20)).toBe(20);
  });
});

